// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
  typeCoercion?: boolean;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ─── Default option values ───────────────────────────────────────────────────

const DEFAULTS: Required<CSVOptions> = {
  delimiter: ",",
  quote: '"',
  lineSeparator: "",   // "" means auto-detect
  typeCoercion: true,
};

// ─── Low-level field tokeniser (handles quoting / escaping) ──────────────────

function tokeniseLine(
  line: string,
  delimiter: string,
  quote: string
): { fields: string[]; error: string | null } {
  const fields: string[] = [];
  let i = 0;
  let error: string | null = null;

  while (i <= line.length) {
    if (i === line.length) {
      // Trailing delimiter produced an empty trailing field — only push if
      // the line actually ended with the delimiter.
      if (fields.length > 0 && line[line.length - 1] === delimiter) {
        fields.push("");
      }
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ──────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      let closed = false;
      while (i < line.length) {
        if (line[i] === quote) {
          if (i + 1 < line.length && line[i + 1] === quote) {
            // Escaped quote
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        error = "Unterminated quoted field";
        // Push what we collected so far and bail
        fields.push(value);
        break;
      }

      fields.push(value);

      // After closing quote we expect either delimiter or end-of-line
      if (i < line.length) {
        if (line[i] === delimiter) {
          i++; // consume delimiter
        } else {
          error = `Unexpected character '${line[i]}' after closing quote`;
          // Try to continue anyway – skip to next delimiter
          while (i < line.length && line[i] !== delimiter) i++;
          if (i < line.length) i++; // skip the delimiter
        }
      }
    } else {
      // ── Unquoted field ────────────────────────────────────────────────
      let value = "";
      while (i < line.length && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      fields.push(value);
      if (i < line.length) i++; // skip delimiter
    }
  }

  // Edge-case: completely empty string → one empty field
  if (fields.length === 0) {
    fields.push("");
  }

  return { fields, error };
}

// ─── Type coercion helper ────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") return null;

  // Boolean
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number – use a strict check so strings like "12abc" stay as strings
  if (/^-?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(value.trim())) {
    const n = Number(value);
    if (!Number.isNaN(n)) return n;
  }

  return value;
}

// ─── Line splitting (respects quoted fields that contain newlines) ───────────

function splitLines(
  input: string,
  lineSep: string,
  quote: string
): string[] {
  if (lineSep) {
    // If the user supplies an explicit separator we still need to respect
    // quotes that may contain that separator.
    const lines: string[] = [];
    let current = "";
    let inQuotes = false;
    let i = 0;
    while (i < input.length) {
      if (input[i] === quote) {
        inQuotes = !inQuotes;
        current += input[i];
        i++;
      } else if (
        !inQuotes &&
        input.substring(i, i + lineSep.length) === lineSep
      ) {
        lines.push(current);
        current = "";
        i += lineSep.length;
      } else {
        current += input[i];
        i++;
      }
    }
    if (current.length > 0) lines.push(current);
    return lines;
  }

  // Auto-detect: handle \r\n, \r, \n – but respect quoted fields
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;
  while (i < input.length) {
    const ch = input[i];
    if (ch === quote) {
      inQuotes = !inQuotes;
      current += ch;
      i++;
    } else if (!inQuotes && (ch === "\r" || ch === "\n")) {
      lines.push(current);
      current = "";
      if (ch === "\r" && i + 1 < input.length && input[i + 1] === "\n") {
        i += 2; // skip \r\n
      } else {
        i++;
      }
    } else {
      current += ch;
      i++;
    }
  }
  if (current.length > 0) lines.push(current);
  return lines;
}

// ─── Build a CSVResult (with methods) from raw data ──────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
      return buildResult(rows.filter(predicate), headers, errors);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") total += v;
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const opts: Required<CSVOptions> = { ...DEFAULTS, ...options };

  // Handle empty / whitespace-only input
  if (!input || input.trim().length === 0) {
    return buildResult([], [], []);
  }

  const lines = splitLines(input, opts.lineSeparator, opts.quote);

  // Remove trailing empty lines
  while (lines.length > 0 && lines[lines.length - 1].trim() === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], []);
  }

  // ── Parse header row ────────────────────────────────────────────────────
  const headerResult = tokeniseLine(lines[0], opts.delimiter, opts.quote);
  const headers = headerResult.fields.map((h) => h.trim());
  const errors: CSVError[] = [];

  if (headerResult.error) {
    errors.push({ row: 1, message: `Header row: ${headerResult.error}` });
  }

  // ── Parse data rows ────────────────────────────────────────────────────
  const rows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    // Skip completely empty lines
    if (line.trim() === "") continue;

    const { fields, error } = tokeniseLine(line, opts.delimiter, opts.quote);
    const rowNum = idx + 1; // 1-based

    if (error) {
      errors.push({ row: rowNum, message: error });
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: rowNum,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
    }

    // Build the row object anyway (with as many fields as we have)
    const row: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      const raw = c < fields.length ? fields[c] : "";
      row[headers[c]] = opts.typeCoercion ? coerce(raw) : raw;
    }
    rows.push(row);
  }

  return buildResult(rows, headers, errors);
}

import { parseCSV } from "./csv-parser";

// ─── tiny assertion helpers ──────────────────────────────────────────────────

let passed = 0;
let failed = 0;
let currentSuite = "";

function suite(name: string) {
  currentSuite = name;
  console.log(`\n━━━ ${name} ━━━`);
}

function assert(condition: boolean, msg: string) {
  if (!condition) {
    failed++;
    console.error(`  ✗ [${currentSuite}] ${msg}`);
    // Throw so the specific test is loud, but we catch in `test()` to keep running
    throw new Error(`Assertion failed: ${msg}`);
  }
}

function eq(actual: unknown, expected: unknown, label: string) {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    console.error(`  ✗ [${currentSuite}] ${label}`);
    console.error(`      expected: ${e}`);
    console.error(`      actual:   ${a}`);
    throw new Error(`Assertion failed: ${label}`);
  }
}

function test(name: string, fn: () => void) {
  try {
    fn();
    passed++;
    console.log(`  ✓ ${name}`);
  } catch (e: any) {
    // Already counted in eq/assert — just log
    console.error(`    → ${e.message}`);
  }
}

// ═════════════════════════════════════════════════════════════════════════════
// TESTS
// ═════════════════════════════════════════════════════════════════════════════

// ─── 1. Basic Parsing ────────────────────────────────────────────────────────

suite("Basic Parsing");

test("parses a simple two-row CSV", () => {
  const csv = "name,age,city\nAlice,30,NYC\nBob,25,LA";
  const result = parseCSV(csv);
  eq(result.headers, ["name", "age", "city"], "headers");
  eq(result.rows.length, 2, "row count");
  eq(result.rows[0]["name"], "Alice", "first row name");
  eq(result.rows[0]["age"], 30, "first row age (coerced)");
  eq(result.rows[1]["city"], "LA", "second row city");
  eq(result.errors.length, 0, "no errors");
});

test("trims header whitespace", () => {
  const csv = " name , age \nAlice,30";
  const result = parseCSV(csv);
  eq(result.headers, ["name", "age"], "trimmed headers");
  eq(result.rows[0]["name"], "Alice", "value accessible via trimmed key");
});

test("handles \\r\\n line endings", () => {
  const csv = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(csv);
  eq(result.rows.length, 2, "row count with CRLF");
  eq(result.rows[1]["a"], 3, "second row first col");
});

test("handles \\r line endings (old Mac)", () => {
  const csv = "a,b\r1,2\r3,4";
  const result = parseCSV(csv);
  eq(result.rows.length, 2, "row count with CR");
});

test("ignores trailing newlines", () => {
  const csv = "a,b\n1,2\n";
  const result = parseCSV(csv);
  eq(result.rows.length, 1, "one data row");
  eq(result.errors.length, 0, "no errors");
});

// ─── 2. Quoted Fields ───────────────────────────────────────────────────────

suite("Quoted Fields");

test("quoted field containing comma", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"';
  const result = parseCSV(csv);
  eq(result.rows[0]["address"], "123 Main St, Apt 4", "comma inside quotes");
});

test("quoted field containing newline", () => {
  const csv = 'name,bio\nAlice,"Line1\nLine2"';
  const result = parseCSV(csv);
  eq(result.rows[0]["bio"], "Line1\nLine2", "newline inside quotes");
  eq(result.rows.length, 1, "still one logical row");
});

test("quoted field that is empty", () => {
  const csv = 'a,b\n"",hello';
  const result = parseCSV(csv);
  eq(result.rows[0]["a"], null, "empty quoted field → null via coercion");
});

test("mixed quoted and unquoted fields", () => {
  const csv = 'a,b,c\nhello,"world",foo';
  const result = parseCSV(csv);
  eq(result.rows[0]["a"], "hello", "unquoted");
  eq(result.rows[0]["b"], "world", "quoted");
  eq(result.rows[0]["c"], "foo", "unquoted");
});

// ─── 3. Escaped Quotes ─────────────────────────────────────────────────────

suite("Escaped Quotes");

test("double-double-quote within quoted field", () => {
  const csv = 'val\n"She said ""hello"""';
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], 'She said "hello"', "escaped quotes");
});

test("field that is just escaped quotes", () => {
  const csv = 'val\n""""""';
  const result = parseCSV(csv);
  eq(result.rows[0]["val"], '""', "three pairs of quotes minus wrapping");
});

test("escaped quote at start and end of value", () => {
  const csv = 'v\n"""hi"""';
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], '"hi"', "quotes wrapping inner content");
});

// ─── 4. Custom Delimiters ───────────────────────────────────────────────────

suite("Custom Delimiters");

test("tab delimiter", () => {
  const csv = "name\tage\nAlice\t30";
  const result = parseCSV(csv, { delimiter: "\t" });
  eq(result.headers, ["name", "age"], "tab headers");
  eq(result.rows[0]["age"], 30, "tab value");
});

test("semicolon delimiter", () => {
  const csv = "a;b;c\n1;2;3";
  const result = parseCSV(csv, { delimiter: ";" });
  eq(result.rows[0]["b"], 2, "semicolon middle value");
});

test("pipe delimiter", () => {
  const csv = "x|y\nhello|world";
  const result = parseCSV(csv, { delimiter: "|" });
  eq(result.rows[0]["x"], "hello", "pipe value");
});

test("custom quote character (single quote)", () => {
  const csv = "a,b\n'hello, world',test";
  const result = parseCSV(csv, { quote: "'" });
  eq(result.rows[0]["a"], "hello, world", "single-quote wrapping");
});

test("custom line separator", () => {
  const csv = "a,b|1,2|3,4";
  const result = parseCSV(csv, { lineSeparator: "|" });
  eq(result.rows.length, 2, "custom line sep row count");
  eq(result.rows[1]["a"], 3, "second row value");
});

// ─── 5. Type Coercion ──────────────────────────────────────────────────────

suite("Type Coercion");

test("integers", () => {
  const csv = "v\n0\n42\n-7";
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], 0, "zero");
  eq(result.rows[1]["v"], 42, "positive int");
  eq(result.rows[2]["v"], -7, "negative int");
});

test("floats", () => {
  const csv = "v\n3.14\n-0.5\n.25";
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], 3.14, "pi-ish");
  eq(result.rows[1]["v"], -0.5, "negative float");
  eq(result.rows[2]["v"], 0.25, "leading dot");
});

test("scientific notation", () => {
  const csv = "v\n1e3\n2.5E-4";
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], 1000, "1e3");
  eq(result.rows[1]["v"], 0.00025, "2.5E-4");
});

test("booleans (case-insensitive)", () => {
  const csv = "v\ntrue\nFalse\nTRUE\nfAlSe";
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], true, "true");
  eq(result.rows[1]["v"], false, "False");
  eq(result.rows[2]["v"], true, "TRUE");
  eq(result.rows[3]["v"], false, "fAlSe");
});

test("null values", () => {
  const csv = "v\nnull\nNULL\n";
  // trailing newline means last line is blank — only two data rows
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], null, "null");
  eq(result.rows[1]["v"], null, "NULL");
});

test("empty string → null", () => {
  const csv = "a,b\n,hello";
  const result = parseCSV(csv);
  eq(result.rows[0]["a"], null, "empty field → null");
});

test("strings that look numeric but are not", () => {
  const csv = "v\n12abc\n1.2.3\nhello";
  const result = parseCSV(csv);
  eq(result.rows[0]["v"], "12abc", "alpha after digits");
  eq(result.rows[1]["v"], "1.2.3", "multiple dots");
  eq(result.rows[2]["v"], "hello", "pure string");
});

test("type coercion disabled", () => {
  const csv = "a,b\n42,true";
  const result = parseCSV(csv, { typeCoercion: false });
  eq(result.rows[0]["a"], "42", "number stays string");
  eq(result.rows[0]["b"], "true", "bool stays string");
});

// ─── 6. Error Handling (malformed rows) ─────────────────────────────────────

suite("Error Handling");

test("row with too few fields", () => {
  const csv = "a,b,c\n1,2";
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "should have at least one error");
  assert(result.errors[0].row === 2, "error on row 2");
  assert(
    result.errors[0].message.includes("Expected 3") &&
      result.errors[0].message.includes("got 2"),
    "message mentions field count"
  );
  // Row should still be created with null for missing column
  eq(result.rows.length, 1, "row is still included");
  eq(result.rows[0]["c"], null, "missing field coerced to null");
});

test("row with too many fields", () => {
  const csv = "a,b\n1,2,3";
  const result = parseCSV(csv);
  assert(result.errors.length > 0, "should report error");
  assert(result.errors[0].message.includes("Expected 2"), "expected 2");
  // Row should still be built with the first N fields
  eq(result.rows[0]["a"], 1, "first field present");
  eq(result.rows[0]["b"], 2, "second field present");
});

test("unterminated quote", () => {
  const csv = 'a,b\n"hello,world';
  const result = parseCSV(csv);
  assert(result.errors.some((e) => e.message.includes("Unterminated")), "unterminated error");
  // Parser should not crash
  assert(result.rows.length >= 0, "parser did not crash");
});

test("multiple errors on different rows", () => {
  const csv = "a,b\n1\n2,3,4\n5,6";
  const result = parseCSV(csv);
  // Row 2 has too few, row 3 has too many
  const row2Errors = result.errors.filter((e) => e.row === 2);
  const row3Errors = result.errors.filter((e) => e.row === 3);
  assert(row2Errors.length > 0, "error on row 2");
  assert(row3Errors.length > 0, "error on row 3");
  eq(result.rows.length, 3, "all rows still included");
  eq(result.rows[2]["a"], 5, "good row after bad rows");
});

test("does not crash on completely garbled input", () => {
  const csv = '"""';
  const result = parseCSV(csv);
  // Just headers, maybe with errors — should not throw
  assert(result !== undefined, "result exists");
});

// ─── 7. Filter ──────────────────────────────────────────────────────────────

suite("Filter");

test("filters rows by predicate", () => {
  const csv = "name,age\nAlice,30\nBob,25\nCharlie,35";
  const result = parseCSV(csv).filter((r) => (r.age as number) >= 30);
  eq(result.rows.length, 2, "two rows match");
  eq(result.rows[0]["name"], "Alice", "Alice matches");
  eq(result.rows[1]["name"], "Charlie", "Charlie matches");
});

test("filter preserves headers and errors", () => {
  const csv = "a,b\n1,2\n3";
  const orig = parseCSV(csv);
  const filtered = orig.filter((r) => r.a === 1);
  eq(filtered.headers, ["a", "b"], "headers preserved");
  eq(filtered.errors.length, orig.errors.length, "errors preserved");
});

test("chained filters", () => {
  const csv = "x,y\n1,a\n2,b\n3,a\n4,a";
  const result = parseCSV(csv)
    .filter((r) => r.y === "a")
    .filter((r) => (r.x as number) > 1);
  eq(result.rows.length, 2, "chained filter count");
  eq(result.rows[0]["x"], 3, "first match");
  eq(result.rows[1]["x"], 4, "second match");
});

test("filter that matches nothing", () => {
  const csv = "a\n1\n2";
  const result = parseCSV(csv).filter(() => false);
  eq(result.rows.length, 0, "empty after filter");
});

// ─── 8. Aggregation: sum ────────────────────────────────────────────────────

suite("Aggregation — sum");

test("sum of numeric column", () => {
  const csv = "item,price\nA,10\nB,20\nC,30";
  eq(parseCSV(csv).sum("price"), 60, "sum = 60");
});

test("sum ignores non-numeric values", () => {
  const csv = "v\n10\nhello\n20\nnull";
  eq(parseCSV(csv).sum("v"), 30, "sum skips strings/nulls");
});

test("sum of column with no numbers", () => {
  const csv = "v\nhello\nworld";
  eq(parseCSV(csv).sum("v"), 0, "sum is 0");
});

test("sum of non-existent column", () => {
  const csv = "a\n1";
  eq(parseCSV(csv).sum("zzz"), 0, "0 for missing column");
});

// ─── 9. Aggregation: average ────────────────────────────────────────────────

suite("Aggregation — average");

test("average of numeric column", () => {
  const csv = "v\n10\n20\n30";
  eq(parseCSV(csv).average("v"), 20, "avg = 20");
});

test("average ignores non-numeric", () => {
  const csv = "v\n10\nhello\n30";
  eq(parseCSV(csv).average("v"), 20, "avg of 10 and 30");
});

test("average of empty / all-non-numeric → 0", () => {
  const csv = "v\nhello";
  eq(parseCSV(csv).average("v"), 0, "avg = 0");
});

// ─── 10. Aggregation: count ─────────────────────────────────────────────────

suite("Aggregation — count");

test("count returns row count", () => {
  const csv = "a\n1\n2\n3";
  eq(parseCSV(csv).count(), 3, "count = 3");
});

test("count after filter", () => {
  const csv = "a\n1\n2\n3\n4\n5";
  eq(
    parseCSV(csv).filter((r) => (r.a as number) > 3).count(),
    2,
    "count after filter = 2"
  );
});

// ─── 11. Aggregation: groupBy ───────────────────────────────────────────────

suite("Aggregation — groupBy");

test("group by string column", () => {
  const csv = "dept,name\nEng,Alice\nHR,Bob\nEng,Charlie\nHR,Diana";
  const groups = parseCSV(csv).groupBy("dept");
  eq(groups.size, 2, "two groups");
  eq(groups.get("Eng")!.length, 2, "Eng has 2");
  eq(groups.get("HR")!.length, 2, "HR has 2");
});

test("group by numeric column", () => {
  const csv = "grade,student\n1,Alice\n2,Bob\n1,Charlie";
  const groups = parseCSV(csv).groupBy("grade");
  eq(groups.get(1)!.length, 2, "grade 1 has 2");
  eq(groups.get(2)!.length, 1, "grade 2 has 1");
});

test("group by column with nulls", () => {
  const csv = "status,v\nactive,1\n,2\nactive,3";
  const groups = parseCSV(csv).groupBy("status");
  assert(groups.has(null), "null group exists");
  eq(groups.get(null)!.length, 1, "null group has 1");
  eq(groups.get("active")!.length, 2, "active group has 2");
});

test("groupBy after filter", () => {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,200\nHR,60";
  const groups = parseCSV(csv)
    .filter((r) => (r.salary as number) > 60)
    .groupBy("dept");
  eq(groups.size, 1, "only Eng remains after filter");
  eq(groups.get("Eng")!.length, 2, "Eng has 2");
});

// ─── 12. Edge Cases ─────────────────────────────────────────────────────────

suite("Edge Cases");

test("empty input", () => {
  const result = parseCSV("");
  eq(result.headers.length, 0, "no headers");
  eq(result.rows.length, 0, "no rows");
  eq(result.errors.length, 0, "no errors");
});

test("whitespace-only input", () => {
