test("group by column with nulls", () => {
  const csv = "status,v\nactive,1\n,2\nactive,3";
  const groups = parseCSV(csv).groupBy("status");
  assert(groups.has(null), "null group exists");
  eq(groups.get(null)!.length, 1, "null group has 1");
  eq(groups.get("active")!.length, 2, "active group has 2");
});

test("groupBy after filter", () => {
  const csv = "dept,salary\nEng,100\nHR,50\nEng,200\nHR,60";
  const groups = parseCSV(csv)
    .filter((r) => (r.salary as number) > 60)
    .groupBy("dept");
  eq(groups.size, 1, "only Eng remains after filter");
  eq(groups.get("Eng")!.length, 2, "Eng has 2");
});

// ─── 12. Edge Cases ─────────────────────────────────────────────────────────

suite("Edge Cases");

